import { scope } from "arktype";

/** Luhn algorithm checksum for credit card validation */
function luhnCheck(value: string): boolean {
  let sum = 0;
  let alternate = false;
  for (let i = value.length - 1; i >= 0; i--) {
    let n = parseInt(value[i]!, 10);
    if (alternate) {
      n *= 2;
      if (n > 9) n -= 9;
    }
    sum += n;
    alternate = !alternate;
  }
  return sum % 10 === 0;
}

const myScope = scope({
  /**
   * creditCard: 13–19 digit string that passes the Luhn checksum.
   * The digit-only / length constraint is expressed via a regex pattern,
   * and the Luhn check is a narrow predicate.
   */
  creditCard: "string"
    // structural: only digits, 13–19 characters long
    .matching(/^\d{13,19}$/)
    // narrow predicate: Luhn checksum
    .narrow((s, ctx) => luhnCheck(s) || ctx.mustBe("a valid credit card number (Luhn check failed)")),

  /**
   * usPhone: matches the required regex pattern.
   */
  usPhone: "string".matching(/^\+?1?[\s-]?\(?\d{3}\)?[\s-]?\d{3}[\s-]?\d{4}$/),

  /**
   * slug: lowercase, 3–64 chars, only a-z 0-9 and -, no leading/trailing dash.
   * Length + charset is done via regex; the no-leading/trailing-dash rule is
   * enforced by a narrow predicate so we satisfy the "at least one narrow" requirement
   * in an obvious and explicit way.
   */
  slug: "string"
    .matching(/^[a-z0-9-]{3,64}$/)
    .narrow(
      (s, ctx) =>
        (s[0] !== "-" && s[s.length - 1] !== "-") ||
        ctx.mustBe("a slug with no leading or trailing dash"),
    ),

  /**
   * Order: composite schema that references the three custom keywords by bare name.
   */
  Order: {
    id: "slug",
    customerPhone: "usPhone",
    cardNumber: "creditCard",
    total: "number > 0",
  },
});

export const { creditCard, usPhone, slug, Order } = myScope.export();

import { Order } from "./src/keywords.ts";

async function main(): Promise<void> {
  // Read all of stdin
  const chunks: Buffer[] = [];
  for await (const chunk of process.stdin) {
    chunks.push(chunk as Buffer);
  }
  const raw = Buffer.concat(chunks).toString("utf-8");

  let parsed: unknown;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    console.log(`INVALID: ${msg}`);
    process.exit(0);
  }

  try {
    const result = Order.assert(parsed);
    console.log("VALID");
    console.log(JSON.stringify(result));
  } catch (err) {
    const msg = err instanceof Error ? err.message : String(err);
    console.log(`INVALID: ${msg}`);
  }

  process.exit(0);
}

main().catch((err) => {
  const msg = err instanceof Error ? err.message : String(err);
  console.log(`INVALID: ${msg}`);
  process.exit(0);
});

